def trap(height):
    if not height:
        return 0
    l, r = 0, len(height) - 1
    lmax, rmax = height[l], height[r]
    total = 0
    while l < r:
        if lmax < rmax:
            l += 1
            lmax = max(lmax, height[l])
            total += lmax - height[l]
        else:
            r -= 1
            rmax = max(rmax, height[r])
            total += rmax - height[r]
    return total

def word_break(s, word_dict):
    words = set(word_dict)
    n = len(s)
    dp = [False] * (n + 1)
    dp[0] = True
    for i in range(1, n + 1):
