def burst_balloons(nums):
    vals = [1] + nums + [1]
    n = len(vals)
    dp = [[0] * n for _ in range(n)]
    for length in range(2, n):
        for left in range(0, n - length):
            right = left + length
            best = 0
            for k in range(left + 1, right):
                cur = vals[left] * vals[k] * vals[right] + dp[left][k] + dp[k][right]
                if cur > best:
                    best = cur
            dp[left][right] = best
    return dp[0][n - 1]

def decode_string(s):
    num_stack = []
    str_stack = []
    cur = ""
    num = 0
    for ch in s:
        if ch.isdigit():
            num = num * 10 + int(ch)
        elif ch == '[':
            num_stack.append(num)
            str_stack.append(cur)
            num = 0
