def longest_consecutive(nums):
    s = set(nums)
    best = 0
    for x in s:
        if x - 1 not in s:
            length = 1
            cur = x
            while cur + 1 in s:
                cur += 1
                length += 1
            best = max(best, length)
    return best

def split_array(nums, k):
    def can(limit):
        count = 1
        cur = 0
        for x in nums:
            if cur + x > limit:
                count += 1
                cur = x
                if count > k:
                    return False
            else:
                cur += x
        return True
    lo, hi = max(nums), sum(nums)
    while lo < hi:
        mid = (lo + hi) // 2
        if can(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo
